questions.question:
What will be the output of the following C code?
int x = 10;
int y = x++ + ++x;
printf("%d", y);

What does the following code print?
int arr[] = {10, 20, 30};
int *ptr = arr;
printf("%d", *(ptr + 1));

What will be the output?
#define SQUARE(x) x*x
printf("%d", SQUARE(3+2));

Consider pointer arithmetic:
int arr[] = {10, 20, 30, 40, 50};
int *ptr = arr;
printf("%d", *(ptr + 2) + *(arr + 1));

Consider the following code:
int x = 10;
int y = 20;
int *p1 = &x;
int *p2 = &y;
*p1 = *p2 + 2;
p1 = p2;
*p2 = 30;
printf("%d %d", x, y);

What will the following code print?
#include <stdio.h>
#define SWAP(a,b) {a=a+b; b=a-b; a=a-b;}
int main() {
    int x = 5, y = 10;
    SWAP(x,y);
    printf("%d %d", x, y);
    return 0;
}

Consider the following code:
int a = 5, b = 10, c = 15;
int *arr[] = {&a, &b, &c};
printf("%d", **arr);
